parameters.jsCode:
const { execSync } = require('child_process');

try {
  // Añadimos un timeout de 30000ms (30 segundos)
  const output = execSync('sh /home/node/.n8n/backup_n8n.sh', { 
    timeout: 30000,
    encoding: 'utf8' 
  });

  return [{
    json: {
      result: "Success",
      output: output
    }
  }];
} catch (error) {
  return [{
    json: {
      result: "Error",
      message: error.message,
      // Si el script dio un error de sistema, esto te lo dirá
      stderr: error.stderr ? error.stderr.toString() : "No stderr output"
    }
  }];
}
